import React, { useState } from 'react';
import './DataTable.css';

const PAGE_SIZE = 10;

export default function DataTable({ data = [], columns = [] }) {
  const [page, setPage] = useState(0);
  const [sortKey, setSortKey]   = useState(null);
  const [sortDir, setSortDir]   = useState('asc');

  if (!data.length) return <p className="table-empty">No data to display.</p>;

  const cols = columns.length ? columns : Object.keys(data[0] || {});

  // Sort
  let rows = [...data];
  if (sortKey) {
    rows.sort((a, b) => {
      const av = a[sortKey], bv = b[sortKey];
      const cmp = typeof av === 'number' ? av - bv : String(av).localeCompare(String(bv));
      return sortDir === 'asc' ? cmp : -cmp;
    });
  }

  const totalPages = Math.ceil(rows.length / PAGE_SIZE);
  const pageRows   = rows.slice(page * PAGE_SIZE, (page + 1) * PAGE_SIZE);

  const handleSort = (key) => {
    if (sortKey === key) setSortDir(d => d === 'asc' ? 'desc' : 'asc');
    else { setSortKey(key); setSortDir('asc'); }
  };

  const fmtVal = (v) => {
    if (v === null || v === undefined) return <span className="null-val">—</span>;
    if (typeof v === 'number')         return v.toLocaleString(undefined, { maximumFractionDigits: 2 });
    return String(v);
  };

  return (
    <div className="data-table-wrapper">
      <div className="table-scroll">
        <table className="data-table">
          <thead>
            <tr>
              {cols.map(col => (
                <th key={col} onClick={() => handleSort(col)} className={sortKey === col ? 'sorted' : ''}>
                  <span>{col.replace(/_/g, ' ')}</span>
                  <span className="sort-indicator">
                    {sortKey === col ? (sortDir === 'asc' ? ' ↑' : ' ↓') : ' ⇅'}
                  </span>
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {pageRows.map((row, ri) => (
              <tr key={ri}>
                {cols.map(col => (
                  <td key={col}>{fmtVal(row[col])}</td>
                ))}
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {totalPages > 1 && (
        <div className="table-pagination">
          <button disabled={page === 0} onClick={() => setPage(0)}>«</button>
          <button disabled={page === 0} onClick={() => setPage(p => p - 1)}>‹</button>
          <span className="page-info">
            {page + 1} / {totalPages}
            <span className="row-count"> · {data.length} rows</span>
          </span>
          <button disabled={page >= totalPages - 1} onClick={() => setPage(p => p + 1)}>›</button>
          <button disabled={page >= totalPages - 1} onClick={() => setPage(totalPages - 1)}>»</button>
        </div>
      )}
    </div>
  );
}
